Unpatched CscQueryDirectory (sub_1C0069FF0):

  length = *(_DWORD *)(a1 + 0x1c8);         // output-buffer length
  ...
  memset(*(void **)(a1 + 0x1b8), 0, length); // zero the buffer to ITS OWN length
  ...
  QueryDirEnumSet(..., *(_QWORD *)(a1 + 0x1b8), length, 0); // capacity = length
  ...
  *(_DWORD *)(a1 + 0x1c8) = length - bytes_written; // remaining-length bookkeeping (buffer/length pairing)

Patched CscQueryDirectory (sub_1C006C180):

  if (Feature_3405715771__private_IsEnabledDeviceUsage()) {
      Src = ExAllocatePoolWithTag(NonPagedPoolNx, /*=*/ length, 0x72447343); // scratch is exactly `length` bytes
      memset(Src, 0, length);
      temp_allocated = 1;
      *(_QWORD *)(a1 + 0x1b8) = Src;            // enumeration targets the scratch
  }
  ... // enumeration writes bounded by length ...
  if (Feature_3405715771__private_IsEnabledDeviceUsage() && temp_allocated) {
      memmove(original_buffer, Src, bytes_written); // bytes_written <= length
      *(_QWORD *)(a1 + 0x1b8) = original_buffer;
  }
  *(_DWORD *)(a1 + 0x1c8) = length - bytes_written; // same bookkeeping
